  alias AdminDashboard.Repo

  @doc """
  Fetches users filtered by role using parameterized queries.

  ## SECURE: Uses $1, $2... placeholders with a params list.
  ## NEVER use string interpolation like "WHERE role='#{role}'" — that is SQL injection.
  """
  def get_users_by_role(role) do
