  """
  def list_users_paginated(page, per_page, role \\ nil) do
    page = max(to_integer(page, 1), 1)
    per_page = min(max(to_integer(per_page, 25), 1), 100)
    offset = (page - 1) * per_page

    {query, params} =
      case role do
        nil ->
          {
            """
            SELECT id, username, email, role, active, inserted_at
            FROM users
            ORDER BY inserted_at DESC
            LIMIT $1 OFFSET $2
            """,
            [per_page, offset]
          }

        role_value ->
