      end
    end)
    |> then(fn {clauses, params, _idx} -> {clauses, params} end)
  end

  defp sanitize_like_pattern(pattern) do
    pattern
    |> String.replace("\\", "\\\\")
    |> String.replace("%", "\\%")
    |> String.replace("_", "\\_")
  end

  defp handle_result({:ok, %Postgrex.Result{columns: columns, rows: rows}}) do
