  @doc """
  Validates that a sort column is allowed. Returns safe column name or default.
  """
  def safe_sort_column(column, default \\ "inserted_at") do
    if to_string(column) in @allowed_sort_columns, do: to_string(column), else: default
  end

  def safe_sort_direction(direction, default \\ "DESC") do
