# lib/admin_dashboard_web/controllers/admin/user_controller.ex
defmodule AdminDashboardWeb.Admin.UserController do
  use AdminDashboardWeb, :controller

  alias AdminDashboard.Queries.UserQueries

  def index(conn, params) do
    page = Map.get(params, "page", "1")
    per_page = Map.get(params, "per_page", "25")
    role = Map.get(params, "role")

    case UserQueries.list_users_paginated(page, per_page, role) do
      {:ok, users} ->
        json(conn, %{data: users})

      {:error, reason} ->
        conn
        |> put_status(:internal_server_error)
        |> json(%{error: "Query failed", detail: reason})
    end
  end

  def search(conn, %{"q" => search_term} = params) do
    role = Map.get(params, "role")

    case UserQueries.search_users(search_term, role) do
      {:ok, users} ->
        json(conn, %{data: users})

      {:error, reason} ->
        conn
        |> put_status(:internal_server_error)
        |> json(%{error: "Search failed", detail: reason})
    end
  end

  def search(conn, _params) do
    conn
    |> put_status(:bad_request)
    |> json(%{error: "Missing required parameter: q"})
  end

  def filter(conn, params) do
    filters =
      params
      |> Map.take(["role", "active", "email", "username"])
      |> Enum.reject(fn {_k, v} -> v == "" or is_nil(v) end)
      |> Map.new()

    case UserQueries.filter_users(filters) do
      {:ok, users} ->
        json(conn, %{data: users})

      {:error, reason} ->
        conn
        |> put_status(:internal_server_error)
        |> json(%{error: "Filter failed", detail: reason})
    end
  end

  def stats(conn, _params) do
    case UserQueries.user_stats() do
      {:ok, stats} ->
        json(conn, %{data: stats})

      {:error, reason} ->
        conn
        |> put_status(:internal_server_error)
        |> json(%{error: "Stats query failed", detail: reason})
    end
  end

  def show(conn, %{"id" => id}) do
    case Integer.parse(id) do
      {int_id, _} ->
        case UserQueries.get_user_by_id(int_id) do
          {:ok, user} -> json(conn, %{data: user})
          {:error, :not_found} -> conn |> put_status(:not_found) |> json(%{error: "User not found"})
          {:error, reason} -> conn |> put_status(:internal_server_error) |> json(%{error: reason})
        end

      :error ->
        conn |> put_status(:bad_request) |> json(%{error: "Invalid user ID"})
    end
  end
end